     1→import { useState } from 'react';
     2→import { GitBranch, Plus, Search, PoundSterling, CheckCircle, Clock, XCircle, Edit2, Trash2, X, TrendingUp, AlertTriangle } from 'lucide-react';
     3→import { useChangeOrders } from '../../hooks/useData';
     4→import { toast } from 'sonner';
     5→
     6→type AnyRow = Record<string, unknown>;
     7→
     8→const STATUS_OPTIONS = ['Draft','Submitted','Under Review','Approved','Rejected','Withdrawn'];
     9→const TYPES = ['Addition','Omission','Substitution','Variation','Provisional Sum'];
    10→const REASONS = ['Client Request','Design Change','Unforeseen Condition','Specification Clarification','Regulatory Requirement','Other'];
    11→
    12→const statusColour: Record<string,string> = {
    13→  'Draft':'bg-gray-100 text-gray-700','Submitted':'bg-blue-100 text-blue-800',
    14→  'Under Review':'bg-yellow-100 text-yellow-800','Approved':'bg-green-100 text-green-800',
    15→  'Rejected':'bg-red-100 text-red-700','Withdrawn':'bg-gray-100 text-gray-500',
    16→};
    17→
    18→const emptyForm = { co_number:'',title:'',type:'Addition',reason:'',value:'',days_extension:'0',status:'Draft',project_id:'',submitted_date:'',approved_date:'',description:'' };
    19→
    20→export function ChangeOrders() {
    21→  const { useList, useCreate, useUpdate, useDelete } = useChangeOrders;
    22→  const { data: raw = [], isLoading } = useList();
    23→  const orders = raw as AnyRow[];
    24→  const createMutation = useCreate();
    25→  const updateMutation = useUpdate();
    26→  const deleteMutation = useDelete();
    27→
    28→  const [subTab, setSubTab] = useState('all');
    29→  const [search, setSearch] = useState('');
    30→  const [statusFilter, setStatusFilter] = useState('All');
    31→  const [showModal, setShowModal] = useState(false);
    32→  function setTab(key: string, filter: string) { setSubTab(key); setStatusFilter(filter); }
    33→  const [editing, setEditing] = useState<AnyRow | null>(null);
    34→  const [form, setForm] = useState({ ...emptyForm });
    35→
    36→  const PENDING_STATUSES = ['Draft','Submitted','Under Review'];
    37→  const REJECTED_STATUSES = ['Rejected','Withdrawn'];
    38→  const filtered = orders.filter(o => {
    39→    const title = String(o.title??'').toLowerCase();
    40→    const num = String(o.co_number??'').toLowerCase();
    41→    const matchSearch = title.includes(search.toLowerCase()) || num.includes(search.toLowerCase());
    42→    let matchStatus = statusFilter === 'All' || o.status === statusFilter;
    43→    if (subTab === 'pending') matchStatus = PENDING_STATUSES.includes(String(o.status??''));
    44→    if (subTab === 'rejected') matchStatus = REJECTED_STATUSES.includes(String(o.status??''));
    45→    return matchSearch && matchStatus;
    46→  });
    47→
    48→  const totalValue = orders.filter(o=>o.status==='Approved').reduce((s,o)=>s+Number(o.value??0),0);
    49→  const pendingValue = orders.filter(o=>['Submitted','Under Review'].includes(String(o.status??''))).reduce((s,o)=>s+Number(o.value??0),0);
    50→  const approvedCount = orders.filter(o=>o.status==='Approved').length;
    51→  const totalDays = orders.filter(o=>o.status==='Approved').reduce((s,o)=>s+Number(o.days_extension??0),0);
    52→
    53→  function nextCONumber() {
    54→    const nums = orders.map(o=>parseInt(String(o.co_number??'0').replace(/\D/g,''))).filter(n=>!isNaN(n));
    55→    const next = nums.length>0?Math.max(...nums)+1:1;
    56→    return `CO-${String(next).padStart(3,'0')}`;
    57→  }
    58→
    59→  function openCreate() { setEditing(null); setForm({ ...emptyForm, co_number:nextCONumber() }); setShowModal(true); }
    60→  function openEdit(o: AnyRow) {
    61→    setEditing(o);
    62→    setForm({ co_number:String(o.co_number??''),title:String(o.title??''),type:String(o.type??'Addition'),reason:String(o.reason??''),value:String(o.value??''),days_extension:String(o.days_extension??'0'),status:String(o.status??'Draft'),project_id:String(o.project_id??''),submitted_date:String(o.submitted_date??''),approved_date:String(o.approved_date??''),description:String(o.description??'') });
    63→    setShowModal(true);
    64→  }
    65→
    66→  async function handleSubmit(e: React.FormEvent) {
    67→    e.preventDefault();
    68→    const payload = { ...form, value:Number(form.value)||0, days_extension:Number(form.days_extension)||0 };
    69→    if (editing) { await updateMutation.mutateAsync({ id:String(editing.id), data:payload }); toast.success('Change order updated'); }
    70→    else { await createMutation.mutateAsync(payload); toast.success('Change order created'); }
    71→    setShowModal(false);
    72→  }
    73→
    74→  async function handleDelete(id: string) {
    75→    if (!confirm('Delete this change order?')) return;
    76→    await deleteMutation.mutateAsync(id); toast.success('Change order deleted');
    77→  }
    78→
    79→  async function approve(o: AnyRow) {
    80→    await updateMutation.mutateAsync({ id:String(o.id), data:{ status:'Approved', approved_date:new Date().toISOString().slice(0,10) } });
    81→    toast.success('Change order approved');
    82→  }
    83→
    84→  return (
    85→    <div className="p-6 space-y-6">
    86→      <div className="flex items-center justify-between">
    87→        <div>
    88→          <h1 className="text-2xl font-bold text-gray-900">Change Orders</h1>
    89→          <p className="text-sm text-gray-500 mt-1">Contract variations, additions & omissions</p>
    90→        </div>
    91→        <button onClick={openCreate} className="flex items-center gap-2 px-4 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700 text-sm font-medium">
    92→          <Plus size={16}/><span>New CO</span>
    93→        </button>
    94→      </div>
    95→
    96→      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
    97→        {[
    98→          { label:'Approved Value', value:`£${totalValue.toLocaleString()}`, icon:PoundSterling, colour:'text-green-600', bg:'bg-green-50' },
    99→          { label:'Pending Value', value:`£${pendingValue.toLocaleString()}`, icon:Clock, colour:'text-yellow-600', bg:'bg-yellow-50' },
   100→          { label:'Approved COs', value:approvedCount, icon:CheckCircle, colour:'text-green-600', bg:'bg-green-50' },
   101→          { label:'Extension Days', value:totalDays, icon:TrendingUp, colour:'text-orange-600', bg:'bg-orange-50' },
   102→        ].map(kpi=>(
   103→          <div key={kpi.label} className="bg-white rounded-xl border border-gray-200 p-4">
   104→            <div className="flex items-center gap-3">
   105→              <div className={`p-2 rounded-lg ${kpi.bg}`}><kpi.icon size={20} className={kpi.colour}/></div>
   106→              <div><p className="text-xs text-gray-500">{kpi.label}</p><p className="text-xl font-bold text-gray-900">{kpi.value}</p></div>
   107→            </div>
   108→          </div>
   109→        ))}
   110→      </div>
   111→
   112→      <div className="flex gap-1 border-b border-gray-200">
   113→        {([
   114→          { key:'all',      label:'All COs',       filter:'All',          count:orders.length },
   115→          { key:'pending',  label:'Pending',        filter:'Submitted',    count:orders.filter(o=>['Draft','Submitted','Under Review'].includes(String(o.status??''))).length },
   116→          { key:'approved', label:'Approved',       filter:'Approved',     count:approvedCount },
   117→          { key:'rejected', label:'Rejected',       filter:'Rejected',     count:orders.filter(o=>['Rejected','Withdrawn'].includes(String(o.status??''))).length },
   118→        ]).map(t=>(
   119→          <button key={t.key} onClick={()=>{ setSubTab(t.key); if(t.key==='pending'){ setStatusFilter('All'); } else { setStatusFilter(t.filter); } }}
