import { useState } from 'react';
import { GitBranch, Plus, Search, PoundSterling, CheckCircle, Clock, XCircle, Edit2, Trash2, X, TrendingUp, AlertTriangle } from 'lucide-react';
import { useChangeOrders } from '../../hooks/useData';
import { toast } from 'sonner';

type AnyRow = Record<string, unknown>;

const STATUS_OPTIONS = ['draft', 'pending', 'approved', 'rejected'];
const REASONS = ['Client Request', 'Design Change', 'Unforeseen Condition', 'Specification Clarification', 'Regulatory Requirement', 'Other'];

const statusColour: Record<string, string> = {
  draft: 'bg-gray-100 text-gray-700',
  pending: 'bg-yellow-100 text-yellow-800',
  approved: 'bg-green-100 text-green-800',
  rejected: 'bg-red-100 text-red-700',
};

const statusLabel: Record<string, string> = {
  draft: 'Draft', pending: 'Pending Approval', approved: 'Approved', rejected: 'Rejected',
};

const emptyForm = {
  number: '', project: '', title: '', description: '', amount: '',
  reason: '', schedule_impact: '0', status: 'draft',
};

export function ChangeOrders() {
  const { useList, useCreate, useUpdate, useDelete } = useChangeOrders;
  const { data: raw = [], isLoading } = useList();
  const orders = raw as AnyRow[];
  const createMutation = useCreate();
  const updateMutation = useUpdate();
  const deleteMutation = useDelete();

  const [statusFilter, setStatusFilter] = useState('all');
  const [search, setSearch] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [editing, setEditing] = useState<AnyRow | null>(null);
  const [form, setForm] = useState({ ...emptyForm });
  const [confirmAction, setConfirmAction] = useState<{ type: 'approve' | 'reject' | 'delete'; item: AnyRow } | null>(null);

  const filtered = orders.filter(o => {
    const title = String(o.title ?? '').toLowerCase();
    const num = String(o.number ?? '').toLowerCase();
    const matchSearch = title.includes(search.toLowerCase()) || num.includes(search.toLowerCase());
    const matchStatus = statusFilter === 'all' || o.status === statusFilter;
    return matchSearch && matchStatus;
  });

  const total = orders.length;
  const pendingCount = orders.filter(o => o.status === 'pending').length;
  const approvedValue = orders.filter(o => o.status === 'approved').reduce((s, o) => s + Number(o.amount ?? 0), 0);
  const rejectedCount = orders.filter(o => o.status === 'rejected').length;

  function nextNumber() {
    const nums = orders.map(o => parseInt(String(o.number ?? '0').replace(/\D/g, ''))).filter(n => !isNaN(n));
    const next = nums.length > 0 ? Math.max(...nums) + 1 : 1;
    return `CO-${String(next).padStart(4, '0')}`;
  }

  function openCreate() {
    setEditing(null);
    setForm({ ...emptyForm, number: nextNumber() });
    setShowModal(true);
  }

  function openEdit(o: AnyRow) {
    setEditing(o);
    setForm({
      number: String(o.number ?? ''),
      project: String(o.project ?? ''),
      title: String(o.title ?? ''),
      description: String(o.description ?? ''),
      amount: String(o.amount ?? ''),
      reason: String(o.reason ?? ''),
      schedule_impact: String(o.schedule_impact ?? o.scheduleImpact ?? '0'),
      status: String(o.status ?? 'draft'),
    });
    setShowModal(true);
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    const payload = { ...form, amount: Number(form.amount) || 0, schedule_impact: Number(form.schedule_impact) || 0 };
    if (editing) {
      await updateMutation.mutateAsync({ id: String(editing.id), data: payload });
    } else {
      await createMutation.mutateAsync(payload);
    }
    setShowModal(false);
  }

  async function handleDelete(o: AnyRow) {
    await deleteMutation.mutateAsync(String(o.id));
    setConfirmAction(null);
    toast.success('Change order deleted');
  }

  async function handleApprove(o: AnyRow) {
    await updateMutation.mutateAsync({ id: String(o.id), data: { status: 'approved', approved_date: new Date().toISOString().slice(0, 10) } });
    setConfirmAction(null);
    toast.success('Change order approved');
  }

  async function handleReject(o: AnyRow) {
    await updateMutation.mutateAsync({ id: String(o.id), data: { status: 'rejected' } });
    setConfirmAction(null);
    toast.success('Change order rejected');
  }

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Change Orders</h1>
          <p className="text-sm text-gray-500 mt-1">Contract variations and scope changes</p>
        </div>
        <button onClick={openCreate} className="flex items-center gap-2 px-4 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700 text-sm font-medium">
          <Plus size={16} /><span>New Change Order</span>
        </button>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label: 'Total', value: total, icon: GitBranch, colour: 'text-blue-600', bg: 'bg-blue-50' },
          { label: 'Pending Approval', value: pendingCount, icon: Clock, colour: 'text-yellow-600', bg: 'bg-yellow-50' },
          { label: 'Approved Value', value: `£${approvedValue.toLocaleString()}`, icon: PoundSterling, colour: 'text-green-600', bg: 'bg-green-50' },
          { label: 'Rejected', value: rejectedCount, icon: XCircle, colour: 'text-red-600', bg: 'bg-red-50' },
        ].map(kpi => (
          <div key={kpi.label} className="bg-white rounded-xl border border-gray-200 p-4">
            <div className="flex items-center gap-3">
              <div className={`p-2 rounded-lg ${kpi.bg}`}><kpi.icon size={20} className={kpi.colour} /></div>
              <div><p className="text-xs text-gray-500">{kpi.label}</p><p className="text-xl font-bold text-gray-900">{kpi.value}</p></div>
            </div>
          </div>
        ))}
      </div>

      <div className="flex gap-1 border-b border-gray-200">
        {([
          { key: 'all', label: 'All', count: orders.length },
          { key: 'pending', label: 'Pending', count: pendingCount },
          { key: 'approved', label: 'Approved', count: orders.filter(o => o.status === 'approved').length },
          { key: 'rejected', label: 'Rejected', count: rejectedCount },
          { key: 'draft', label: 'Draft', count: orders.filter(o => o.status === 'draft').length },
        ]).map(t => (
          <button key={t.key} onClick={() => setStatusFilter(t.key)}
            className={`flex items-center gap-2 px-4 py-2.5 text-sm font-medium border-b-2 -mb-px transition-colors ${statusFilter === t.key ? 'border-orange-600 text-orange-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}>
            {t.label}
            <span className="text-xs px-1.5 py-0.5 rounded-full bg-gray-100 text-gray-600">{t.count}</span>
          </button>
        ))}
      </div>

      <div className="flex flex-wrap gap-3 items-center bg-white rounded-xl border border-gray-200 p-4">
        <div className="relative flex-1 min-w-48">
          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
          <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search number or title…" className="w-full pl-9 pr-4 py-2 text-sm border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500" />
        </div>
        <select value={statusFilter} onChange={e => setStatusFilter(e.target.value)} className="text-sm border border-gray-200 rounded-lg px-3 py-2 focus:outline-none focus:ring-2 focus:ring-orange-500">
          <option value="all">All Statuses</option>
          {STATUS_OPTIONS.map(s => <option key={s} value={s}>{statusLabel[s]}</option>)}
        </select>
        <span className="text-sm text-gray-500 ml-auto">{filtered.length} change orders</span>
      </div>

      {isLoading ? (
        <div className="flex justify-center py-20"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-orange-600" /></div>
      ) : (
        <div className="bg-white rounded-xl border border-gray-200 overflow-hidden">
          <table className="w-full">
            <thead className="bg-gray-50 border-b border-gray-200">
              <tr>{['CO #', 'Project', 'Title', 'Amount', 'Schedule Impact', 'Reason', 'Status', 'Submitted', ''].map(h => (
                <th key={h} className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider whitespace-nowrap">{h}</th>
              ))}</tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {filtered.map(o => (
                <tr key={String(o.id)} className="hover:bg-gray-50">
                  <td className="px-4 py-3 font-mono text-xs font-bold text-orange-600">{String(o.number ?? '—')}</td>
                  <td className="px-4 py-3 text-gray-600 text-sm">{String(o.project ?? '—')}</td>
                  <td className="px-4 py-3 font-medium text-gray-900 max-w-xs truncate">{String(o.title ?? '—')}</td>
                  <td className="px-4 py-3 font-semibold text-gray-900">£{Number(o.amount ?? 0).toLocaleString()}</td>
                  <td className="px-4 py-3 text-gray-600 text-sm">{Number(o.schedule_impact ?? o.scheduleImpact ?? 0) > 0 ? `+${o.schedule_impact ?? o.scheduleImpact}d` : '—'}</td>
                  <td className="px-4 py-3 text-gray-500 text-sm">{String(o.reason ?? '—')}</td>
                  <td className="px-4 py-3">
                    <span className={`text-xs px-2 py-1 rounded-full font-medium ${statusColour[String(o.status ?? '')] ?? 'bg-gray-100 text-gray-700'}`}>
                      {statusLabel[String(o.status ?? '')] ?? String(o.status ?? '')}
                    </span>
                  </td>
                  <td className="px-4 py-3 text-gray-500 text-sm">{String(o.submitted_date ?? o.submittedDate ?? '—')}</td>
                  <td className="px-4 py-3">
                    <div className="flex items-center gap-1">
                      {o.status === 'pending' && <>
                        <button onClick={() => setConfirmAction({ type: 'approve', item: o })} className="p-1.5 text-green-600 hover:bg-green-50 rounded" title="Approve"><CheckCircle size={14} /></button>
                        <button onClick={() => setConfirmAction({ type: 'reject', item: o })} className="p-1.5 text-red-600 hover:bg-red-50 rounded" title="Reject"><XCircle size={14} /></button>
                      </>}
                      <button onClick={() => openEdit(o)} className="p-1.5 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded"><Edit2 size={14} /></button>
                      <button onClick={() => setConfirmAction({ type: 'delete', item: o })} className="p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded"><Trash2 size={14} /></button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {filtered.length === 0 && (
            <div className="text-center py-16 text-gray-400">
              <GitBranch size={40} className="mx-auto mb-3 opacity-30" />
              <p className="font-medium">No change orders found</p>
              <p className="text-sm mt-1">Create your first change order using the button above</p>
            </div>
          )}
        </div>
      )}

      {showModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto">
            <div className="flex items-center justify-between p-6 border-b sticky top-0 bg-white z-10">
              <h2 className="text-lg font-semibold">{editing ? 'Edit Change Order' : 'New Change Order'}</h2>
              <button onClick={() => setShowModal(false)} className="p-2 hover:bg-gray-100 rounded-lg"><X size={18} /></button>
            </div>
            <form onSubmit={handleSubmit} className="p-6 space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">CO Number</label>
                  <input value={form.number} onChange={e => setForm(f => ({ ...f, number: e.target.value }))} className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm font-mono focus:outline-none focus:ring-2 focus:ring-orange-500" />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Project</label>
                  <input value={form.project} onChange={e => setForm(f => ({ ...f, project: e.target.value }))} placeholder="Project name" className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-orange-500" />
                </div>
                <div className="col-span-2">
                  <label className="block text-sm font-medium text-gray-700 mb-1">Title *</label>
                  <input required value={form.title} onChange={e => setForm(f => ({ ...f, title: e.target.value }))} className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-orange-500" />
                </div>
                <div className="col-span-2">
                  <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
                  <textarea rows={3} value={form.description} onChange={e => setForm(f => ({ ...f, description: e.target.value }))} className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-orange-500 resize-none" />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Amount (£)</label>
                  <input type="number" step="0.01" value={form.amount} onChange={e => setForm(f => ({ ...f, amount: e.target.value }))} className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-orange-500" />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Schedule Impact (days)</label>
                  <input type="number" value={form.schedule_impact} onChange={e => setForm(f => ({ ...f, schedule_impact: e.target.value }))} className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-orange-500" />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Reason</label>
                  <select value={form.reason} onChange={e => setForm(f => ({ ...f, reason: e.target.value }))} className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-orange-500">
                    <option value="">Select reason…</option>
                    {REASONS.map(r => <option key={r}>{r}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Status</label>
                  <select value={form.status} onChange={e => setForm(f => ({ ...f, status: e.target.value }))} className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-orange-500">
                    {STATUS_OPTIONS.map(s => <option key={s} value={s}>{statusLabel[s]}</option>)}
                  </select>
                </div>
              </div>
              <div className="flex gap-3 pt-2">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-2 border border-gray-200 rounded-lg text-sm text-gray-700 hover:bg-gray-50">Cancel</button>
                <button type="submit" disabled={createMutation.isPending || updateMutation.isPending} className="flex-1 px-4 py-2 bg-orange-600 text-white rounded-lg text-sm font-medium hover:bg-orange-700 disabled:opacity-50">
                  {editing ? 'Update Change Order' : 'Create Change Order'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {confirmAction && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-sm p-6">
            <div className="flex items-center gap-3 mb-4">
              {confirmAction.type === 'delete' ? (
                <div className="p-2 bg-red-100 rounded-lg"><Trash2 size={20} className="text-red-600" /></div>
              ) : confirmAction.type === 'approve' ? (
                <div className="p-2 bg-green-100 rounded-lg"><CheckCircle size={20} className="text-green-600" /></div>
              ) : (
                <div className="p-2 bg-orange-100 rounded-lg"><AlertTriangle size={20} className="text-orange-600" /></div>
              )}
              <div>
                <h3 className="font-semibold text-gray-900">
                  {confirmAction.type === 'delete' ? 'Delete Change Order' : confirmAction.type === 'approve' ? 'Approve Change Order' : 'Reject Change Order'}
                </h3>
                <p className="text-sm text-gray-500">
                  {confirmAction.type === 'delete'
                    ? `Are you sure you want to delete "${String(confirmAction.item.title ?? '')}"?`
                    : confirmAction.type === 'approve'
                    ? `Approve change order "${String(confirmAction.item.number ?? '')}"?`
                    : `Reject change order "${String(confirmAction.item.number ?? '')}"?`}
                </p>
              </div>
            </div>
            <div className="flex gap-3">
              <button onClick={() => setConfirmAction(null)} className="flex-1 px-4 py-2 border border-gray-200 rounded-lg text-sm text-gray-700 hover:bg-gray-50">Cancel</button>
              <button
                onClick={() => {
                  if (confirmAction.type === 'delete') handleDelete(confirmAction.item);
                  else if (confirmAction.type === 'approve') handleApprove(confirmAction.item);
                  else handleReject(confirmAction.item);
                }}
                className={`flex-1 px-4 py-2 rounded-lg text-sm font-medium text-white ${confirmAction.type === 'approve' ? 'bg-green-600 hover:bg-green-700' : 'bg-red-600 hover:bg-red-700'}`}
              >
                {confirmAction.type === 'delete' ? 'Delete' : confirmAction.type === 'approve' ? 'Approve' : 'Reject'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

